(()=>{const a=document.querySelectorAll('.reveal');if(!('IntersectionObserver'in window)){a.forEach(e=>e.classList.add('is-visible'));return}const b=new IntersectionObserver((c,d)=>{for(const e of c)e.isIntersecting&&(e.target.classList.add('is-visible'),d.unobserve(e))},{threshold:.12});a.forEach(e=>b.observe(e))})()